import React from 'react';
import './styles/skeleton.css';

export type SkeletonVariant  = 'default' | 'shimmer' | 'wave' | 'pulse';
export type SkeletonShape    = 'rectangle' | 'circle' | 'rounded' | 'pill';
export type SkeletonSize     = 'sm' | 'md' | 'lg';

export interface SkeletonProps {
  variant?  : SkeletonVariant;
  shape?    : SkeletonShape;
  width?    : string | number;
  height?   : string | number;
  size?     : SkeletonSize;
  className?: string;
  style?    : React.CSSProperties;
}

export interface SkeletonTextProps {
  lines?    : number;
  variant?  : SkeletonVariant;
  lastLineWidth?: string;
  gap?      : string | number;
  size?     : SkeletonSize;
  className?: string;
}

export interface SkeletonAvatarProps {
  size?     : SkeletonSize | number;
  variant?  : SkeletonVariant;
  shape?    : 'circle' | 'rounded';
  className?: string;
}

export interface SkeletonCardProps {
  variant?    : SkeletonVariant;
  hasAvatar?  : boolean;
  hasImage?   : boolean;
  lines?      : number;
  hasActions? : boolean;
  className?  : string;
}

export interface SkeletonTableProps {
  rows?     : number;
  cols?     : number;
  variant?  : SkeletonVariant;
  hasHeader?: boolean;
  className?: string;
}

const avatarSizeMap: Record<string, string> = {
  sm: '32px',
  md: '40px',
  lg: '56px',
};

export function Skeleton({
  variant   = 'shimmer',
  shape     = 'rectangle',
  width,
  height,
  size      = 'md',
  className = '',
  style,
}: SkeletonProps) {
  const cls = [
    'sk-base',
    `sk-variant-${variant}`,
    `sk-shape-${shape}`,
    `sk-size-${size}`,
    className,
  ].filter(Boolean).join(' ');

  const inlineStyle: React.CSSProperties = {
    ...(width  !== undefined ? { width:  typeof width  === 'number' ? `${width}px`  : width  } : {}),
    ...(height !== undefined ? { height: typeof height === 'number' ? `${height}px` : height } : {}),
    ...style,
  };

  return <div className={cls} style={inlineStyle} aria-hidden="true" />;
}

export function SkeletonText({
  lines        = 3,
  variant      = 'shimmer',
  lastLineWidth = '60%',
  gap          = 8,
  size         = 'md',
  className    = '',
}: SkeletonTextProps) {
  return (
    <div
      className={['sk-text-block', className].filter(Boolean).join(' ')}
      style={{ display:'flex', flexDirection:'column', gap: typeof gap === 'number' ? `${gap}px` : gap }}
      aria-hidden="true"
    >
      {Array.from({ length: lines }).map((_, i) => (
        <Skeleton
          key={i}
          variant={variant}
          shape="pill"
          size={size}
          width={i === lines - 1 && lines > 1 ? lastLineWidth : '100%'}
        />
      ))}
    </div>
  );
}

export function SkeletonAvatar({
  size      = 'md',
  variant   = 'shimmer',
  shape     = 'circle',
  className = '',
}: SkeletonAvatarProps) {
  const dim = typeof size === 'number' ? `${size}px` : avatarSizeMap[size] ?? '40px';
  return (
    <Skeleton
      variant={variant}
      shape={shape === 'circle' ? 'circle' : 'rounded'}
      width={dim}
      height={dim}
      className={className}
    />
  );
}

export function SkeletonCard({
  variant    = 'shimmer',
  hasAvatar  = true,
  hasImage   = false,
  lines      = 3,
  hasActions = false,
  className  = '',
}: SkeletonCardProps) {
  return (
    <div className={['sk-card', className].filter(Boolean).join(' ')} aria-hidden="true">
      {hasImage && (
        <Skeleton variant={variant} shape="rectangle" width="100%" height={180} className="sk-card-image" />
      )}
      <div className="sk-card-body">
        {hasAvatar && (
          <div className="sk-card-header">
            <SkeletonAvatar variant={variant} size="md" />
            <div style={{ flex:1, display:'flex', flexDirection:'column', gap:6 }}>
              <Skeleton variant={variant} shape="pill" width="40%" height={12} />
              <Skeleton variant={variant} shape="pill" width="28%" height={10} />
            </div>
          </div>
        )}
        <SkeletonText variant={variant} lines={lines} />
        {hasActions && (
          <div className="sk-card-actions">
            <Skeleton variant={variant} shape="pill" width={80} height={32} />
            <Skeleton variant={variant} shape="pill" width={80} height={32} />
          </div>
        )}
      </div>
    </div>
  );
}

export function SkeletonTable({
  rows      = 4,
  cols      = 4,
  variant   = 'shimmer',
  hasHeader = true,
  className = '',
}: SkeletonTableProps) {
  return (
    <div className={['sk-table', className].filter(Boolean).join(' ')} aria-hidden="true">
      {hasHeader && (
        <div className="sk-table-row sk-table-header">
          {Array.from({ length: cols }).map((_, i) => (
            <Skeleton key={i} variant={variant} shape="pill" height={12} width={i === 0 ? '60%' : '80%'} />
          ))}
        </div>
      )}
      {Array.from({ length: rows }).map((_, r) => (
        <div key={r} className="sk-table-row">
          {Array.from({ length: cols }).map((_, c) => (
            <Skeleton key={c} variant={variant} shape="pill" height={12}
              width={c === 0 ? '50%' : c === cols - 1 ? '30%' : '90%'} />
          ))}
        </div>
      ))}
    </div>
  );
}

export default Skeleton;

:root {
  --sk-base-color   : #e2e8f0;
  --sk-high-color   : #f1f5f9;
  --sk-radius-sm    : 4px;
  --sk-radius-md    : 6px;
  --sk-radius-lg    : 8px;
  --sk-duration     : 1.5s;

  --sk-h-sm : 10px;
  --sk-h-md : 14px;
  --sk-h-lg : 18px;
}

@media (prefers-color-scheme: dark) {
  :root {
    --sk-base-color : #1e293b;
    --sk-high-color : #334155;
  }
}

.sk-base {
  display         : block;
  background-color: var(--sk-base-color);
  width           : 100%;
  height          : var(--sk-h-md);
  border-radius   : var(--sk-radius-md);
  flex-shrink     : 0;
}

.sk-size-sm { height: var(--sk-h-sm); }
.sk-size-md { height: var(--sk-h-md); }
.sk-size-lg { height: var(--sk-h-lg); }

.sk-shape-circle    { border-radius: 50%; }
.sk-shape-pill      { border-radius: 9999px; }
.sk-shape-rounded   { border-radius: var(--sk-radius-lg); }
.sk-shape-rectangle { border-radius: var(--sk-radius-md); }

.sk-variant-default { background-color: var(--sk-base-color); }

.sk-variant-pulse {
  background-color: var(--sk-base-color);
  animation       : sk-pulse var(--sk-duration) ease-in-out infinite;
}

@keyframes sk-pulse {
  0%, 100% { opacity: 1;    }
  50%       { opacity: 0.45; }
}

.sk-variant-shimmer {
  background: var(--sk-base-color);
  background-image: linear-gradient(
    90deg,
    var(--sk-base-color) 0%,
    var(--sk-high-color) 40%,
    var(--sk-high-color) 60%,
    var(--sk-base-color) 100%
  );
  background-size  : 200% 100%;
  background-repeat: no-repeat;
  animation        : sk-shimmer var(--sk-duration) linear infinite;
}

@keyframes sk-shimmer {
  0%   { background-position: 200% center; }
  100% { background-position: -200% center; }
}

.sk-variant-wave {
  background: var(--sk-base-color);
  overflow  : hidden;
  position  : relative;
}
.sk-variant-wave::after {
  content   : '';
  position  : absolute;
  inset     : 0;
  background: linear-gradient(90deg, transparent 0%, var(--sk-high-color) 50%, transparent 100%);
  transform : translateX(-100%);
  animation : sk-wave var(--sk-duration) ease-in-out infinite;
}
@keyframes sk-wave {
  0%   { transform: translateX(-100%); }
  100% { transform: translateX(100%);  }
}

.sk-card {
  border       : 0.5px solid #e2e8f0;
  border-radius: 0.75rem;
  overflow     : hidden;
  background   : #ffffff;
}

.sk-card-image { border-radius: 0; display: block; }

.sk-card-body {
  padding       : 1rem 1.25rem;
  display       : flex;
  flex-direction: column;
  gap           : 1rem;
}

.sk-card-header {
  display    : flex;
  align-items: center;
  gap        : 0.75rem;
}

.sk-card-actions {
  display: flex;
  gap    : 0.625rem;
  padding-top: 0.25rem;
}

.sk-table {
  display       : flex;
  flex-direction: column;
  border        : 0.5px solid #e2e8f0;
  border-radius : 0.5rem;
  overflow      : hidden;
}

.sk-table-row {
  display    : flex;
  align-items: center;
  gap        : 1rem;
  padding    : 0.75rem 1rem;
  border-bottom: 0.5px solid #e2e8f0;
}
.sk-table-row:last-child { border-bottom: none; }

.sk-table-row > .sk-base { flex: 1; }

.sk-table-header {
  background: #f8fafc;
}
